// Check that the scraper exited cleanly.
const item = items[0];
const exitCode = item.json.exitCode;
const stderr = item.json.stderr || '';
const stdout = item.json.stdout || '';

if (exitCode !== 0) {
  throw new Error(`Facebook scraper failed (exit ${exitCode}). stderr: ${stderr.slice(0, 500)}`);
}

return [{ json: { exitCode, stdout: stdout.slice(-2000), stderr: stderr.slice(-500), scraper_ok: true } }];

// Read the CSV file produced by the scraper.
const fs = require('fs');
const path = require('path');

const scriptDir = '{{SCRIPT_DIR}}';
const outputFile = '{{OUTPUT_FILE}}';
const fullPath = path.isAbsolute(outputFile) ? outputFile : path.join(scriptDir, outputFile);

if (!fs.existsSync(fullPath)) {
  return [{ json: { events: [], count: 0, message: `Output file not found: ${fullPath}` } }];
}

const raw = fs.readFileSync(fullPath, 'utf8');
return [{ json: { csv_raw: raw, file_path: fullPath } }];

// Parse CSV rows into event objects.
const csvRaw = items[0].json.csv_raw || '';
if (!csvRaw.trim()) {
  return [{ json: { events: [], count: 0 } }];
}

const lines = csvRaw.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { events: [], count: 0 } }];
}

// Parse header
const header = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));

const events = [];
for (let i = 1; i < lines.length; i++) {
  const cols = [];
  let cur = '';
  let inQuote = false;
  for (const ch of lines[i]) {
    if (ch === '"') { inQuote = !inQuote; }
    else if (ch === ',' && !inQuote) { cols.push(cur); cur = ''; }
    else { cur += ch; }
  }
  cols.push(cur);
  if (cols.length < 2) continue;
  const obj = {};
  header.forEach((h, idx) => { obj[h] = (cols[idx] || '').trim(); });
  events.push(obj);
}

return [{ json: { events, count: events.length } }];
